CREATE EXTENSION IF NOT EXISTS "pgcrypto";
CREATE TABLE "users" ("id" TEXT NOT NULL DEFAULT gen_random_uuid()::text,"username" TEXT NOT NULL,"password_hash" TEXT NOT NULL,"display_name" TEXT NOT NULL,"is_active" BOOLEAN NOT NULL DEFAULT true,"created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updated_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "users_pkey" PRIMARY KEY ("id"));
CREATE TABLE "work_orders" ("id" TEXT NOT NULL DEFAULT gen_random_uuid()::text,"code" TEXT NOT NULL,"product_name" TEXT NOT NULL,"stage" TEXT NOT NULL,"progress" INTEGER NOT NULL DEFAULT 0,"priority" TEXT NOT NULL DEFAULT 'normal',"status" TEXT NOT NULL DEFAULT 'processing',"created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updated_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "work_orders_pkey" PRIMARY KEY ("id"));
CREATE TABLE "resource_categories" ("id" TEXT NOT NULL DEFAULT gen_random_uuid()::text,"name" TEXT NOT NULL,"code" TEXT NOT NULL,"sort_order" INTEGER NOT NULL DEFAULT 0,"created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updated_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "resource_categories_pkey" PRIMARY KEY ("id"));
CREATE TABLE "resource_files" ("id" TEXT NOT NULL DEFAULT gen_random_uuid()::text,"work_order_id" TEXT NOT NULL,"category_id" TEXT NOT NULL,"original_name" TEXT NOT NULL,"mime_type" TEXT NOT NULL,"file_type" TEXT NOT NULL,"file_size" INTEGER NOT NULL,"object_key" TEXT NOT NULL,"version" TEXT NOT NULL DEFAULT 'V1.0',"status" TEXT NOT NULL DEFAULT 'uploaded',"uploaded_by_id" TEXT,"created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"updated_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,"deleted_at" TIMESTAMP(3),CONSTRAINT "resource_files_pkey" PRIMARY KEY ("id"));
CREATE TABLE "operation_logs" ("id" TEXT NOT NULL DEFAULT gen_random_uuid()::text,"user_id" TEXT,"action" TEXT NOT NULL,"target_type" TEXT,"target_id" TEXT,"detail" JSONB,"created_at" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP,CONSTRAINT "operation_logs_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX "users_username_key" ON "users"("username");
CREATE UNIQUE INDEX "work_orders_code_key" ON "work_orders"("code");
CREATE UNIQUE INDEX "resource_categories_code_key" ON "resource_categories"("code");
CREATE INDEX "resource_files_work_order_id_category_id_status_deleted_at_idx" ON "resource_files"("work_order_id","category_id","status","deleted_at");
CREATE INDEX "operation_logs_user_id_idx" ON "operation_logs"("user_id");
ALTER TABLE "resource_files" ADD CONSTRAINT "resource_files_work_order_id_fkey" FOREIGN KEY ("work_order_id") REFERENCES "work_orders"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "resource_files" ADD CONSTRAINT "resource_files_category_id_fkey" FOREIGN KEY ("category_id") REFERENCES "resource_categories"("id") ON DELETE RESTRICT ON UPDATE CASCADE;
ALTER TABLE "resource_files" ADD CONSTRAINT "resource_files_uploaded_by_id_fkey" FOREIGN KEY ("uploaded_by_id") REFERENCES "users"("id") ON DELETE SET NULL ON UPDATE CASCADE;
ALTER TABLE "operation_logs" ADD CONSTRAINT "operation_logs_user_id_fkey" FOREIGN KEY ("user_id") REFERENCES "users"("id") ON DELETE SET NULL ON UPDATE CASCADE;
